-- Generated by infa2dbt
{{ config(materialized='view') }}

WITH router_input AS (
    SELECT * FROM {{ ref('int_material_master_with_flags') }}
),

insert_records AS (
    SELECT *
    FROM router_input
    WHERE Insert_Update_FLAG = 'I'
),

update_records AS (
    SELECT *
    FROM router_input
    WHERE Insert_Update_FLAG = 'U'
),

default_records AS (
    SELECT *
    FROM router_input
    WHERE Insert_Update_FLAG NOT IN ('I', 'U')
)

SELECT
    'INSERT' AS record_type,
    *
FROM insert_records

UNION ALL

SELECT
    'UPDATE' AS record_type,
    *
FROM update_records

UNION ALL

SELECT
    'DEFAULT' AS record_type,
    *
FROM default_records
